    // Binding Configuration Factory
    public static class SecureBindingFactory
    {
        /// <summary>
        /// Creates a WS-Security compliant binding with message-level encryption
        /// using mutual X.509 certificate authentication.
        /// </summary>
        public static CustomBinding CreateSecureBinding()
        {
            var securityElement = SecurityBindingElement.CreateMutualCertificateBindingElement(
                MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

            // Configure encryption algorithm suite - AES-256 for HIPAA compliance
            securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

            // Require encryption and signing of all message parts
            securityElement.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;

            // Enable secure session for replay protection
            securityElement.IncludeTimestamp = true;
            securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;

            // Set reasonable timeouts
            securityElement.LocalClientSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            securityElement.LocalServiceSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            securityElement.LocalServiceSettings.DetectReplays = true;
            securityElement.LocalServiceSettings.ReplayWindow = TimeSpan.FromMinutes(5);
            securityElement.LocalServiceSettings.MaxPendingSessions = 100;

            // Text message encoding with UTF-8
            var textEncoding = new TextMessageEncodingBindingElement
            {
                MessageVersion = MessageVersion.Soap12WSAddressing10,
                WriteEncoding = System.Text.Encoding.UTF8
            };

            // HTTPS transport
            var httpsTransport = new HttpsTransportBindingElement
            {
                RequireClientCertificate = true,
                MaxReceivedMessageSize = 1048576, // 1 MB max
                MaxBufferSize = 1048576,
                TransferMode = TransferMode.Buffered
            };

            var binding = new CustomBinding(securityElement, textEncoding, httpsTransport);
            binding.ReceiveTimeout = TimeSpan.FromMinutes(10);
            binding.SendTimeout = TimeSpan.FromMinutes(10);

            return binding;
        }

        /// <summary>
        /// Creates a binding using WS-Security with username/password over certificate encryption.
        /// Suitable for scenarios where client certificates are not available.
        /// </summary>
        public static CustomBinding CreateSecureBindingWithUsernameAuth()
        {
            var securityElement = SecurityBindingElement.CreateUserNameOverTransportBindingElement();

            securityElement.IncludeTimestamp = true;
            securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;
            securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;
            securityElement.LocalServiceSettings.DetectReplays = true;

            var textEncoding = new TextMessageEncodingBindingElement
            {
                MessageVersion = MessageVersion.Soap12WSAddressing10,
                WriteEncoding = System.Text.Encoding.UTF8
            };

            var httpsTransport = new HttpsTransportBindingElement
            {
                MaxReceivedMessageSize = 1048576,
                MaxBufferSize = 1048576
            };

            return new CustomBinding(securityElement, textEncoding, httpsTransport);
        }
    }

    // Service Host Configuration
    public class SecureServiceHostFactory
    {
        public static ServiceHost CreateServiceHost(
            string baseAddress,
            string serviceCertificateThumbprint,
            StoreLocation certStoreLocation = StoreLocation.LocalMachine)
        {
            var host = new ServiceHost(typeof(HealthcareRecordsServiceImpl), new Uri(baseAddress));

            // Add service endpoint with secure binding
            var binding = SecureBindingFactory.CreateSecureBinding();
            var endpoint = host.AddServiceEndpoint(
                typeof(IHealthcareRecordsService),
                binding,
                "HealthcareRecords");

            // Configure service certificate
            host.Credentials.ServiceCertificate.SetCertificate(
                certStoreLocation,
                StoreName.My,
                X509FindType.FindByThumbprint,
                serviceCertificateThumbprint);

            // Configure client certificate authentication
            host.Credentials.ClientCertificate.Authentication.CertificateValidationMode =
                X509CertificateValidationMode.ChainTrust;
            host.Credentials.ClientCertificate.Authentication.RevocationMode =
                X509RevocationMode.Online;

            // Service throttling for availability
            var throttle = host.Description.Behaviors.Find<ServiceThrottlingBehavior>();
            if (throttle == null)
            {
                throttle = new ServiceThrottlingBehavior();
                host.Description.Behaviors.Add(throttle);
            }
            throttle.MaxConcurrentCalls = 50;
            throttle.MaxConcurrentInstances = 50;
            throttle.MaxConcurrentSessions = 100;

            // Disable metadata publishing in production
            var metadataBehavior = host.Description.Behaviors.Find<ServiceMetadataBehavior>();
            if (metadataBehavior != null)
            {
                metadataBehavior.HttpGetEnabled = false;
                metadataBehavior.HttpsGetEnabled = false;
            }

            // Service debug behavior - disable exception details in production
            var debugBehavior = host.Description.Behaviors.Find<ServiceDebugBehavior>();
            if (debugBehavior == null)
            {
                debugBehavior = new ServiceDebugBehavior();
                host.Description.Behaviors.Add(debugBehavior);
            }
            debugBehavior.IncludeExceptionDetailInFaults = false;

            return host;
        }
    }

    // Client Proxy Factory
    public static class SecureClientFactory
    {
        public static ChannelFactory<IHealthcareRecordsService> CreateClientFactory(
            string endpointAddress,
            string clientCertificateThumbprint,
            string serviceCertificateThumbprint,
            StoreLocation certStoreLocation = StoreLocation.LocalMachine)
        {
            var binding = SecureBindingFactory.CreateSecureBinding();

            var endpointAddr = new EndpointAddress(
                new Uri(endpointAddress),
                EndpointIdentity.CreateX509CertificateIdentity(
                    FindCertificate(serviceCertificateThumbprint, certStoreLocation)));

            var factory = new ChannelFactory<IHealthcareRecordsService>(binding, endpointAddr);

            // Set client certificate
            factory.Credentials.ClientCertificate.SetCertificate(
                certStoreLocation,
                StoreName.My,
                X509FindType.FindByThumbprint,
                clientCertificateThumbprint);

            // Configure service certificate validation
            factory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
                X509CertificateValidationMode.ChainTrust;
            factory.Credentials.ServiceCertificate.Authentication.RevocationMode =
                X509RevocationMode.Online;

            return factory;
        }

        private static X509Certificate2 FindCertificate(string thumbprint, StoreLocation storeLocation)
        {
            using (var store = new X509Store(StoreName.My, storeLocation))
            {
                store.Open(OpenFlags.ReadOnly);
                var certs = store.Certificates.Find(X509FindType.FindByThumbprint, thumbprint, true);

                if (certs.Count == 0)
                    throw new InvalidOperationException($"Certificate with thumbprint '{thumbprint}' not found.");

                return certs[0];
            }
        }
    }

    // Program entry point demonstrating service hosting
    public class Program
    {
        public static void Main(string[] args)
        {
            // Configuration values - in production, load from secure configuration
            string baseAddress = "https://localhost:8443/";
            string serviceCertThumbprint = "YOUR_SERVICE_CERT_THUMBPRINT_HERE";

            Console.WriteLine("Healthcare Records SOAP Service - HIPAA Compliant");
            Console.WriteLine("=================================================");

            try
            {
                using (var host = SecureServiceHostFactory.CreateServiceHost(baseAddress, serviceCertThumbprint))
                {
                    host.Open();

                    Console.WriteLine($"Service started at: {baseAddress}HealthcareRecords");
                    Console.WriteLine("Security: WS-Security with mutual X.509 certificate authentication");
                    Console.WriteLine("Encryption: AES-256 with SHA-256 signatures");
                    Console.WriteLine("Transport: HTTPS with client certificate requirement");
                    Console.WriteLine();
                    Console.WriteLine("Press Enter to stop the service...");
                    Console.ReadLine();

                    host.Close();
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error starting service: {ex.Message}");

                // Demonstrate in-memory usage without actual WCF hosting
                Console.WriteLine();
                Console.WriteLine("Running in-memory demonstration...");
                RunDemonstration();
            }
        }

        private static void RunDemonstration()
        {
            var service = new HealthcareRecordsServiceImpl(new AuditLogger());

            // Create a patient record
            var patient = new PatientRecord
            {
                PatientId = "PAT-001",
                FirstName = "John",
                LastName = "Doe",
                DateOfBirth = new DateTime(1985, 6, 15),
                SocialSecurityNumber = "123-45-6789",
                MedicalHistory = new List<MedicalEntry>(),
                CurrentMedications = new List<Medication>(),
                Insurance = new InsuranceInfo
                {
                    ProviderId = "INS-001",
                    ProviderName = "HealthCare Plus",
                    PolicyNumber = "POL-12345",
                    GroupNumber = "GRP-001"
                }
            };

            Console.WriteLine("Creating patient record...");
            var createResult = service.CreatePatientRecord(patient);
            Console.WriteLine($"  Result: {createResult.Success} - {createResult.Message} (Correlation: {createResult.CorrelationId})");

            // Add medical entry
            Console.WriteLine("Adding medical entry...");
            var entry = new MedicalEntry
            {
                Date = DateTime.UtcNow,
                DiagnosisCode = "J06.9",
                Description = "Upper respiratory infection",
                ProviderId = "DR-001",
                ProviderName = "Dr Smith",
                Notes = "Patient presents with cough and congestion"
            };
            var entryResult = service.AddMedicalEntry("PAT-001", entry);
            Console.WriteLine($"  Result: {entryResult.Success} - {entryResult.Message}");

            // Add medication
            Console.WriteLine("Adding medication...");
            var medication = new Medication
            {
                Name = "Amoxicillin",
                Dosage = "500mg",
                Frequency = "Three times daily",
                PrescribedDate = DateTime.UtcNow,
                PrescriberId = "DR-001"
            };
            var medResult = service.AddMedication("PAT-001", medication);
            Console.WriteLine($"  Result: {medResult.Success} - {medResult.Message}");

            // Retrieve patient record
            Console.WriteLine("Retrieving patient record...");
            var searchCriteria = new PatientSearchCriteria { PatientId = "PAT-001" };
            var getResult = service.GetPatientRecord(searchCriteria);
            Console.WriteLine($"  Result: {getResult.Success} - Patient: {getResult.Record?.FirstName} {getResult.Record?.LastName}");
            Console.WriteLine($"  Medical entries: {getResult.Record?.MedicalHistory?.Count ?? 0}");
            Console.WriteLine($"  Medications: {getResult.Record?.CurrentMedications?.Count ?? 0}");

            // Test validation
            Console.WriteLine("Testing input validation...");
            try
            {
                var invalidCriteria = new PatientSearchCriteria();
                service.GetPatientRecord(invalidCriteria);
            }
            catch (FaultException<HealthcareFault> ex)
            {
                Console.WriteLine($"  Expected fault: {ex.Detail.FaultCode} - {ex.Detail.FaultMessage}");
            }

            Console.WriteLine();
            Console.WriteLine("Demonstration complete.");
        }
    }
